#include <stdio.h>
#include <stdlib.h>
#define MOD 1000003
long long power(long long a, long long b, long long mod) {
    long long res = 1;
    while (b > 0) {
        if (b & 1)
            res = (res * a) % mod;
        a = (a * a) % mod;
        b >>= 1;
    }
    return res;
}
long long inv(long long a, long long mod) {
    return power(a, mod - 2, mod);
}
long long nCr(long long n, long long r, long long mod) {
    long long num = 1, den = 1;
    for (long long i = 1; i <= r; i++) {
        num = (num * (n - i + 1)) % mod;
        den = (den * i) % mod;
    }
    return (num * inv(den, mod)) % mod;
}
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        long long n, l, r;
        scanf("%lld %lld %lld", &n, &l, &r);
        long long ans = 0;
        for (long long i = 1; i <= n; i++) {
            long long x = r - l + 1;
            ans = (ans + nCr(x + i - 1, i, MOD)) % MOD;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

