import java.util.Scanner;
public class Main {
    static final long MOD = 1000003;
    public static long power(long a, long b, long mod) {
        long res = 1;
        while (b > 0) {
            if (b % 2 == 1)
                res = (res * a) % mod;
            a = (a * a) % mod;
            b >>= 1;
        }
        return res;
    }
    public static long inv(long a, long mod) {
        return power(a, mod - 2, mod);
    }
    public static long nCr(long n, long r, long mod) {
        long num = 1, den = 1;
        for (long i = 1; i <= r; i++) {
            num = (num * (n - i + 1)) % mod;
            den = (den * i) % mod;
        }
        return (num * inv(den, mod)) % mod;
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            long n = sc.nextLong(), l = sc.nextLong(), r = sc.nextLong();
            long ans = 0;
            for (long i = 1; i <= n; i++) {
                long x = r - l + 1;
                ans = (ans + nCr(x + i - 1, i, MOD)) % MOD;
            }
            System.out.println(ans);
        }
    }
}

